OPCODES = {
    0x00: "HALT", 0x01: "CONST_", 0x02: "PUSH", 0x03: "POP",
    0x04: "INC", 0x05: "DEC", 0x06: "ADD", 0x07: "SUB",
    0x08: "MUL", 0x09: "DIV", 0x0A: "AND", 0x0B: "OR",
    0x0C: "XOR", 0x0D: "NOT", 0x0E: "SHL", 0x0F: "SHR",
    0x11: "JMP", 0x12: "CMPJE", 0x13: "CMPJNE",
    0x14: "CMPJG", 0x15: "CMPJGE", 0x16: "CMPJL",
    0x17: "CMPJLE", 0x18: "DUP", 0x19: "CALL",
    0x1A: "RET", 0x1B: "SYSCALL", 0x1C: "MOV",
    0x1D: "MOD", 0x1E: "LOADIND", 0x1F: "STOREIND",
    0x20: "PRINT", 0x21: "SCAN", 0x3F: "NOP", 0x7F: "SWAP",
}

ONE_ARG = {
    0x01, 0x02, 0x03,
    0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17,
    0x19, 0x20, 0x21,
}


def disasm(code, encrypted=True, stop_on_halt=True):
    ip = 0

    while ip < len(code):
        cur = ip
        raw = code[ip] & 0xFFFF
        op = raw ^ (0xB00B ^ ip) if encrypted else raw
        op &= 0xFFFF
        ip += 1

        name = OPCODES.get(op)

        if name is None:
            print(f"{cur:04d}: DB 0x{raw:04X} ; decoded=0x{op:04X}")
            continue

        if op in ONE_ARG:
            arg = code[ip] & 0xFFFF
            ip += 1
            print(f"{cur:04d}: {name} {arg}")
        elif op == 0x1C:
            dest_type = code[ip]
            src_type = code[ip + 1]
            src = code[ip + 2]
            ip += 3

            s = f"{cur:04d}: MOV dest_type={dest_type}, src_type={src_type}, src={src}"

            if src_type == 2:
                imm = code[ip]
                ip += 1
                s += f", imm={imm}"

            dest = code[ip]
            ip += 1
            s += f", dest={dest}"

            print(s)
        else:
            print(f"{cur:04d}: {name}")

        if op == 0x00 and stop_on_halt:
            break


